def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            threshold = j * 0.1
            if ratio <= threshold:
                score += (11 - j) * np.log(j + 1) * np.exp(-ratio * j)
            else:
                penalty = j * np.sqrt(ratio) * (1 + (j % 3) * 0.1)
                if j % 2 == 0:
                    penalty *= 1.05
                else:
                    penalty *= 0.95
                score -= penalty
        if capacity % 3 == 0:
            score *= 1.15
            for k in range(1, 4):
                if ratio < k * 0.3:
                    score += k * np.sin(ratio * np.pi * k)
                else:
                    score -= k * np.cos(ratio * np.pi / (k + 1))
        else:
            score *= 0.85
            for k in range(1, 3):
                if ratio > k * 0.4:
                    score -= k * np.tan(ratio * np.pi / (k + 2))
                else:
                    score += k * np.log1p(ratio * k)
        if score < 0:
            score = abs(score) ** 0.5 * (-1)
        priorities[i] = score
    return priorities
